  1	import * as React from 'react';
  2	import {
  3	  FormGroup,
  4	  FormHelperText,
  5	  HelperText,
  6	  HelperTextItem,
  7	} from '@patternfly/react-core';
  8	import classNames from 'classnames';
  9	import { useField } from 'formik';
 10	import { getFieldId } from '../pipelines-details/multi-column-field/utils';
 11	import { RedExclamationCircleIcon } from '@openshift-console/dynamic-plugin-sdk';
 12	import RadioButtonField from './RadioButtonField';
 13	import { FieldProps } from '../pipelines-details/multi-column-field/types';
 14	
 15	import './RadioGroupField.scss';
 16	
 17	interface RadioGroupOption {
 18	  value: React.ReactText;
 19	  label: React.ReactNode;
 20	  isDisabled?: boolean;
 21	  isChecked?: boolean;
 22	  children?: React.ReactNode;
 23	  activeChildren?: React.ReactElement;
 24	}
 25	
 26	interface RadioGroupFieldProps extends FieldProps {
 27	  isInline?: boolean;
 28	  labelIcon?: React.ReactElement;
 29	  options: RadioGroupOption[];
 30	  onChange?: (value: React.ReactText) => void;
 31	}
 32	
 33	const RadioGroupField: React.FC<RadioGroupFieldProps> = ({
 34	  label,
 35	  labelIcon,
 36	  options,
 37	  helpText,
 38	  required,
 39	  isInline,
 40	  onChange,
 41	  ...props
 42	}) => {
 43	  const [field, { touched, error }] = useField(props.name);
 44	  const fieldId = getFieldId(props.name, 'radiogroup');
 45	  const isValid = !(touched && error);
 46	  const errorMessage = !isValid ? error : '';
 47	  return (
 48	    <FormGroup
 49	      className={classNames('ocs-radio-group-field', {
 50	        'ocs-radio-group-field--inline': isInline,
 51	      })}
 52	      fieldId={fieldId}
 53	      isRequired={required}
 54	      label={label}
 55	      labelHelp={labelHelp}
 56	      isInline={isInline}
 57	    >
 58	      {options.map((option) => {
 59	        const activeChild =
 60	          field.value === option.value && option.activeChildren;
 61	        const staticChild = option.children;
 62	
 63	        const description = (activeChild || staticChild) && (
 64	          <div className="ocs-radio-group-field__children">
 65	            {staticChild}
 66	            {activeChild}
 67	          </div>
 68	        );
 69	
 70	        return (
 71	          <React.Fragment key={option.value}>
 72	            <RadioButtonField
 73	              {...field}
 74	              {...props}
 75	              value={option.value}
 76	              label={option.label}
 77	              isDisabled={option.isDisabled}
 78	              isChecked={option.isChecked}
 79	              aria-describedby={helpText ? `${fieldId}-helper` : undefined}
 80	              description={description}
 81	              onChange={onChange}
 82	            />
 83	          </React.Fragment>
 84	        );
 85	      })}
 86	
 87	      <FormHelperText>
 88	        <HelperText>
 89	          {!isValid ? (
 90	            <HelperTextItem variant="error" icon={<RedExclamationCircleIcon />}>
 91	              {errorMessage}
 92	            </HelperTextItem>
 93	          ) : (
 94	            <HelperTextItem>{helpText}</HelperTextItem>
 95	          )}
 96	        </HelperText>
 97	      </FormHelperText>
 98	    </FormGroup>
 99	  );
100	};
101	
102	export default RadioGroupField;

